module top_module( clk, clrn, NPC, PC );input              clk;
  input              clrn;
  input       [31:0] NPC;
  output reg  [31:0] PC;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk, negedge clrn or posedge dbg_halt)
    if (clrn==0) 
      PC <= 32'h0000_0000;

    else
      PC <= NPC;

endmodule
